def make_alternate_pattern(s: str) -> str:
    n = len(s)
    if n == 0:
        return ""

    flips_to_01_pattern = 0
    flips_to_10_pattern = 0

    # Calculate flips needed to achieve '0101...' pattern
    for i in range(n):
        expected_char_01 = '0' if i % 2 == 0 else '1'
        if s[i] != expected_char_01:
            flips_to_01_pattern += 1

    # Calculate flips needed to achieve '1010...' pattern
    for i in range(n):
        expected_char_10 = '1' if i % 2 == 0 else '0'
        if s[i] != expected_char_10:
            flips_to_10_pattern += 1

    # Determine which pattern requires fewer flips or if tied, prefer '0101...'
    if flips_to_01_pattern <= flips_to_10_pattern:
        result_chars = []
        for i in range(n):
            result_chars.append('0' if i % 2 == 0 else '1')
        return "".join(result_chars)
    else:
        result_chars = []
        for i in range(n):
            result_chars.append('1' if i % 2 == 0 else '0')
        return "".join(result_chars)
